def _make_key(self, model: str, messages: list, **kwargs) -> str:
    key_data = {
        "model": model,
        "messages": messages,
        "temperature": kwargs.get("temperature", 1.0),
        "max_tokens": kwargs.get("max_tokens"),
    }
    return hashlib.sha256(
        json.dumps(key_data, sort_keys=True).encode()
    ).hexdigest()
